\documentclass[11pt]{article}
\usepackage[margin=1in]{geometry}
\usepackage{amsmath,amssymb,amsfonts,mathtools}
\usepackage{array,booktabs,enumitem,graphicx,xcolor,hyperref}
\usepackage[T1]{fontenc}
\usepackage[utf8]{inputenc}
\title{On the Dynamics of Light Wilson Quarks}
\author{Source-backed arXiv sample}
\date{}
\begin{document}
\maketitle
\section{Figure Captions}

\begin{figure}[htbp]
\centering
\fbox{\rule{0pt}{1.15in}\rule{0.78\linewidth}{0pt}}
\caption{Time history of the effective pion mass (distance \$8\$) for \$\textbackslash{}beta=5.30\$ and \$\textbackslash{}kappa=0.1677\$ on a \$16\textasciicircum{}3\textbackslash{}times 32\$ lattice. Symbols are: (\$\textbackslash{}times\$) HMC at \$\textbackslash{}delta\textbackslash{}tau=0.0069\$, (\$+\$) HMD at \$\textbackslash{}delta\textbackslash{}tau=0.0069\$, (\$\textbackslash{}bigcirc\$) HMD at \$\textbackslash{}delta\textbackslash{}tau=0.004\$. Also shown is the blocksize\$=40\$ (\$\textbackslash{}Diamond\$) HMC acceptance uncorrected for autocorrelations.}
\label{fig:source-1}
\end{figure}


Figures~\ref{fig:source-1} through~\ref{fig:source-1} preserve source-backed captions while replacing external graphics with deterministic placeholders.
\end{document}

